mapper.insert:
/* 리뷰: 저장 */
INSERT INTO REVIEW (
    TRD_SN, REVWR_USR_SN, REVWD_USR_SN, RVW_DOMAIN_CD, RVW_SCORE, RVW_CN
) VALUES (
    #{trdSn}, #{revwrUsrSn}, #{revwdUsrSn}, #{rvwDomainCd}, #{rvwScore}, #{rvwCn}
)

mapper.update:
/* 리뷰: 수정 */
UPDATE REVIEW
   SET RVW_SCORE = #{rating},
       RVW_CN    = #{content}
 WHERE RVW_SN = #{rvwSn}
   AND REVWR_USR_SN = #{usrSn}
   AND RVW_USE_YN = 'Y'

/* 리뷰: 소프트 삭제 */
UPDATE REVIEW
   SET RVW_USE_YN = 'N'
 WHERE RVW_SN = #{rvwSn}
   AND REVWR_USR_SN = #{usrSn}
   AND RVW_USE_YN = 'Y'

mapper.select:
/* 리뷰: 특정 회원이 받은 리뷰 목록 (F-COM-008) */ SELECT R.RVW_SN AS reviewId, R.RVW_SCORE AS rating, R.RVW_CN AS content, DATE_FORMAT(R.RVW_REG_DT, '%Y-%m-%d') AS createdDate, CASE WHEN T.TRD_TYPE_CD = 'TRDC0001' THEN 'goods' ELSE 'service' END AS dealType, T.TRD_SN AS tradeId, CASE WHEN T.TRD_TYPE_CD = 'TRDC0001' THEN T.PRD_SN ELSE T.SVC_REQ_SN END AS productId, CASE WHEN T.TRD_TYPE_CD = 'TRDC0001' THEN P.PRD_NM ELSE S.SVC_REQ_TTL END AS productTitle, U.USR_NM AS reviewerName, R.REVWR_USR_SN AS reviewerUsrSn FROM REVIEW R JOIN TRADE T ON T.TRD_SN = R.TRD_SN LEFT JOIN PRODUCT P ON T.TRD_TYPE_CD = 'TRDC0001' AND P.PRD_SN = T.PRD_SN LEFT JOIN SERVICE_REQUEST S ON T.TRD_TYPE_CD = 'TRDC0002' AND S.SVC_REQ_SN = T.SVC_REQ_SN JOIN USERS U ON U.USR_SN = R.REVWR_USR_SN WHERE R.REVWD_USR_SN = #{usrSn} AND R.RVW_USE_YN = 'Y'
AND T.TRD_TYPE_CD = 'TRDC0001'
AND T.TRD_TYPE_CD = 'TRDC0002'
ORDER BY R.RVW_REG_DT DESC LIMIT #{size} OFFSET #{offset}

/* 리뷰: 특정 회원이 받은 리뷰 수 (F-COM-008 페이지네이션) */ SELECT COUNT(*) FROM REVIEW R JOIN TRADE T ON T.TRD_SN = R.TRD_SN WHERE R.REVWD_USR_SN = #{usrSn} AND R.RVW_USE_YN = 'Y'
AND T.TRD_TYPE_CD = 'TRDC0001'
AND T.TRD_TYPE_CD = 'TRDC0002'
